// node_conv_232 : pointwise 1x1 conv2d, tiled-streaming contract.
//   IC=512, OC=128, IH=IW=28 (stride=1), MP=4, channel_tile=32.
//   IN_BEATS=16, OUT_BEATS=4, OC_PASSES=32.
//   Latency = IN_BEATS + OC_PASSES*(MP*K_TOTAL + 6) = 16 + 32*2054 = 65744.
module node_conv_232 (
    input  wire         clk,
    input  wire         rst_n,
    input  wire         valid_in,
    output reg          ready_in,
    input  wire [255:0] data_in,
    output reg          valid_out,
    output reg  [255:0] data_out
);

    localparam IC          = 512;
    localparam OC          = 128;
    localparam IH          = 28;
    localparam IW          = 28;
    localparam OH          = 28;
    localparam OW          = 28;
    localparam KH          = 1;
    localparam KW          = 1;
    localparam K_TOTAL     = IC * KH * KW;
    localparam MP          = 4;
    localparam OC_PASSES   = (OC + MP - 1) / MP;
    localparam CHANNEL_TILE = 32;
    localparam IN_BEATS    = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam OUT_BEATS   = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam TILE_BITS   = CHANNEL_TILE * 8;

    localparam SCALE_MULT  = 29831;
    localparam SCALE_SHIFT = 21;

    localparam PROD_W        = 16;
    localparam ACC_W         = 26;
    localparam BIAS_W        = 32;
    localparam BIASED_W      = 34;
    localparam SCALE_CONST_W = 16;
    localparam SCALED_W      = BIASED_W + SCALE_CONST_W;

    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    (* rom_style="block", ram_style="block" *) reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style="block", ram_style="block" *) reg signed [31:0] biases  [0:OC-1];

    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_232_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_232_bias.hex", biases);
    end

    reg signed [7:0] in_latch [0:IC-1];
    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [BIASED_W-1:0] biased [0:MP-1];
    reg signed [SCALED_W-1:0] scaled [0:MP-1];
    reg [OC*8-1:0] out_pack;

    reg signed [7:0]                          weight_q;
    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;
    reg                                       mac_valid_q1, mac_valid_q2;
    reg [1:0]                                 mac_lane_q1, mac_lane_q2;
    reg [9:0]                                 mac_k_q1;

    reg [4:0]  in_beat_idx;
    reg [2:0]  out_beat_idx;
    reg [5:0]  oc_group;
    reg [2:0]  lane_counter;
    reg [9:0]  k_counter;
    reg [10:0] active_emit_count;
    reg [1:0]  drain_cnt;
    reg        mac_done_issuing;

    localparam ST_LOAD       = 3'd0;
    localparam ST_PASS_SETUP = 3'd1;
    localparam ST_RUNNING    = 3'd2;
    localparam ST_BIAS       = 3'd3;
    localparam ST_SCALE      = 3'd4;
    localparam ST_OUTPUT     = 3'd5;
    localparam ST_EMIT       = 3'd6;
    reg [2:0] state;

    integer ch;
    integer lane;
    reg signed [SCALED_W-1:0] v_tmp;

    wire [15:0] weight_addr;
    assign weight_addr = (oc_group * MP + lane_counter) * K_TOTAL + k_counter;

    always @(posedge clk) begin
        if (state == ST_LOAD && valid_in && ready_in) begin
            for (ch = 0; ch < CHANNEL_TILE; ch = ch + 1)
                in_latch[in_beat_idx * CHANNEL_TILE + ch] <= $signed(data_in[ch*8 +: 8]);
        end
        if (state == ST_PASS_SETUP) begin
            for (lane = 0; lane < MP; lane = lane + 1)
                acc[lane] <= {ACC_W{1'b0}};
        end else if (mac_valid_q2) begin
            acc[mac_lane_q2] <= acc[mac_lane_q2] + mul_q;
        end
        if (state == ST_BIAS) begin
            for (lane = 0; lane < MP; lane = lane + 1)
                biased[lane] <= $signed(acc[lane]) + $signed(biases[oc_group * MP + lane]);
        end
        if (state == ST_SCALE) begin
            for (lane = 0; lane < MP; lane = lane + 1)
                scaled[lane] <= $signed(biased[lane]) * $signed(SCALE_MULT_CONST);
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= ST_LOAD; ready_in <= 1'b1; valid_out <= 1'b0; data_out <= 256'd0;
            in_beat_idx <= 0; out_beat_idx <= 0; oc_group <= 0; lane_counter <= 0;
            k_counter <= 0; active_emit_count <= 0; drain_cnt <= 0;
            mac_done_issuing <= 0; mac_valid_q1 <= 0; mac_valid_q2 <= 0;
            mac_lane_q1 <= 0; mac_lane_q2 <= 0; mac_k_q1 <= 0;
            weight_q <= 0; mul_q <= 0; out_pack <= 0;
        end else begin
            weight_q     <= weights[weight_addr];
            mul_q        <= $signed(weight_q) * $signed(in_latch[mac_k_q1]);
            mac_valid_q2 <= mac_valid_q1;
            mac_lane_q2  <= mac_lane_q1;
            case (state)
                ST_LOAD: begin
                    valid_out <= 1'b0;
                    if (valid_in && ready_in) begin
                        if (in_beat_idx == IN_BEATS - 1) begin
                            in_beat_idx <= 0; ready_in <= 1'b0; oc_group <= 0; state <= ST_PASS_SETUP;
                        end else in_beat_idx <= in_beat_idx + 1;
                    end
                end
                ST_PASS_SETUP: begin
                    k_counter <= 0; lane_counter <= 0; mac_valid_q1 <= 0;
                    mac_done_issuing <= 0; drain_cnt <= 0; state <= ST_RUNNING;
                end
                ST_RUNNING: begin
                    if (!mac_done_issuing) begin
                        mac_valid_q1 <= 1'b1; mac_lane_q1 <= lane_counter[1:0]; mac_k_q1 <= k_counter;
                        if (lane_counter == MP - 1) begin
                            lane_counter <= 0;
                            if (k_counter == K_TOTAL - 1) begin mac_done_issuing <= 1; drain_cnt <= 0; end
                            else k_counter <= k_counter + 1;
                        end else lane_counter <= lane_counter + 1;
                    end else begin
                        mac_valid_q1 <= 0;
                        if (drain_cnt == 2'd1) state <= ST_BIAS;
                        drain_cnt <= drain_cnt + 1;
                    end
                end
                ST_BIAS:  state <= ST_SCALE;
                ST_SCALE: state <= ST_OUTPUT;
                ST_OUTPUT: begin
                    for (lane = 0; lane < MP; lane = lane + 1) begin
                        v_tmp = (scaled[lane] + (scaled[lane][SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
                        out_pack[(oc_group * MP + lane) * 8 +: 8] <= (v_tmp > 127) ? 8'sd127 : (v_tmp < -128) ? -8'sd128 : v_tmp[7:0];
                    end
                    if (oc_group == OC_PASSES - 1) begin
                        valid_out <= 1'b1; data_out <= out_pack[0 +: TILE_BITS];
                        out_beat_idx <= 0; oc_group <= 0; state <= ST_EMIT;
                    end else begin oc_group <= oc_group + 1; state <= ST_PASS_SETUP; end
                end
                ST_EMIT: begin
                    if (out_beat_idx == OUT_BEATS - 1) begin
                        valid_out <= 1'b0; ready_in <= 1'b1; out_beat_idx <= 0;
                        if (active_emit_count == OH*OW - 1) active_emit_count <= 0;
                        else active_emit_count <= active_emit_count + 1;
                        state <= ST_LOAD;
                    end else begin
                        data_out <= out_pack[(out_beat_idx + 3'd1) * TILE_BITS +: TILE_BITS];
                        out_beat_idx <= out_beat_idx + 1;
                    end
                end
                default: state <= ST_LOAD;
            endcase
        end
    end
endmodule
